LinearLayout.View:


                window.inlineFunctionForGroupieDragAndDrop = function(fragment, command, obj, groupieBuilder, visible, gone) {
                    var carousel = groupieBuilder.withSection("carousel");
                    for (var i=0; i< 10; i++) {
                        carousel.addItem({"background" : "#0f0", "name": i + ""});
                    }
                    carousel.updateSection("title", "Carousel").updateSection("subtitle", "Swipe this section horizontally to scroll into the items.").updateSection("visibility",gone).updateSection("subtitlevisibility");

                    var data = groupieBuilder
                            .withSection("test").addItem({"a" : "1"}).addItem({"a" : "2"})
                            .withSection("test1").addItem({"name" : "A", subitems: [{"a" : "Apple"}, {"a" : "Andy"}]}).addItem({"name" : "B", subitems: [{"a" : "Banana"}, {"a" : "Boy"}, {"a" : "Bat"}]})
                            .withSection("fullbleeditem").updateSection("title", "A Full Bleed Item").updateSection("subtitle", "").updateSection("visibility", gone).updateSection("subitems", [{"background" : "#f00", "name": ""}])
                            .withSection("grid").updateSection("title", "Multiple Columns With Even Spacing").updateSection("subtitle", "").updateSection("visibility",gone).updateSection("subitems", [{"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}])
                            .withSection("expand").updateSection("title", "Expand Group").updateSection("subtitle", "Tap on header to expand or contract the group").updateSection("visibility",visible).updateSection("subtitlevisibility",visible).updateSection('icon', '@drawable/icon_expand').updateSection("subitems", [{"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}, {"background" : "#ff0", "name": ""}])
                            .getSectionData();

                    command.setVisibility(visible).updateModelData("sectionInfo->view as pathmap", data).notifyDataSetChanged(true);
		            fragment.executeCommand(command);
                }
